class Board:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.initialize_board()

    def initialize_board(self):
        # Initialize pieces for both players
        for i in range(3):
            for j in (1, 3, 5, 7):
                if (i + j) % 2 == 1:
                    self.board[i, j] = 1
        for i in range(5, 8):
            for j in (0, 2, 4, 6):
                if (i + j) % 2 == 1:
                    self.board[i, j] = -1

    def get_piece(self, row, col):
        return self.board[row, col]

    def set_piece(self, row, col, value):
        self.board[row, col] = value

    def is_valid_move(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if piece == 0:
            return False
        if (piece > 0 and end_row >= start_row) or (piece < 0 and end_row <= start_row):
            return False

        # Check for single move
        if abs(end_row - start_row) == 1 and abs(end_col - start_col) == 1:
            if self.get_piece(end_row, end_col) == 0:
                return True

        # Check for capture
        if abs(end_row - start_row) == 2 and abs(end_col - start_col) == 2:
            middle_piece = self.get_piece((start_row + end_row) // 2, (start_col + end_col) // 2)
            if middle_piece != -piece and middle_piece != 0:
                self.set_piece((start_row + end_row) // 2, (start_col + end_col) // 2, 0)
                return True

        return False
